// ---- CONFIG (placeholders, replaced by sync to live n8n) ----
const TELEGRAM_BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';
const ALLOWED_CHAT_IDS  = [935389847];
const LAUNCHER_URL      = 'http://10.1.4.232:8765';
const LAUNCHER_SECRET   = 'YOUR_LAUNCHER_SECRET';
const MLFLOW_URL        = 'http://10.1.4.230:5000';
const RUNPOD_API_KEY    = 'YOUR_RUNPOD_API_KEY';
const RUNPOD_POD_ID     = 'YOUR_RUNPOD_POD_ID';

// HTML escape — Telegram parse_mode HTML treats <,>,& specially
function esc(s) {
  if (s == null) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

async function tgSend(chat_id, text) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: { chat_id, text, parse_mode: 'HTML', disable_web_page_preview: true },
    json: true,
    timeout: 10000,
    failOnNotOk: false,
  });
}

// ---- POLL TELEGRAM getUpdates (long-poll) ----
const staticData = $getWorkflowStaticData('global');
const lastOffset = staticData.lastOffset || 0;

let updates = [];
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getUpdates`,
    qs: { offset: lastOffset + 1, timeout: 25, allowed_updates: 'message' },
    json: true,
    timeout: 30000,
  });
  if (r.ok && Array.isArray(r.result)) updates = r.result;
} catch (e) {
  return [];
}

if (updates.length === 0) return [];
staticData.lastOffset = Math.max(...updates.map(u => u.update_id));

// ---- DATA HELPERS ----
async function gqlRunPod(query) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.runpod.io/graphql',
    headers: { 'Authorization': `Bearer ${RUNPOD_API_KEY}`, 'Content-Type': 'application/json' },
    body: { query },
    json: true,
    timeout: 8000,
    failOnNotOk: false,
  });
}

async function getRunPodStatus() {
  try {
    const q = `query { pod(input: {podId: "${RUNPOD_POD_ID}"}) { id name desiredStatus costPerHr runtime { uptimeInSeconds gpus { gpuUtilPercent memoryUtilPercent } } } }`;
    const r = await gqlRunPod.call(this, q);
    return r.data?.pod;
  } catch (e) { return { _error: String(e).slice(0,200) }; }
}

async function getRunPodBalance() {
  try {
    const r = await gqlRunPod.call(this, `query { myself { clientBalance } }`);
    return r.data?.myself?.clientBalance;
  } catch (e) { return null; }
}

async function getLauncherStatus() {
  try {
    return await this.helpers.httpRequest({ url: `${LAUNCHER_URL}/status`, json: true, timeout: 5000, failOnNotOk: false });
  } catch (e) { return { _error: 'launcher unreachable' }; }
}

async function getMLflowExperimentIds() {
  try {
    const r = await this.helpers.httpRequest({
      url: `${MLFLOW_URL}/api/2.0/mlflow/experiments/search`,
      method: 'POST',
      body: { max_results: 50, view_type: 'ALL' },
      json: true,
      timeout: 5000,
      failOnNotOk: false,
    });
    return (r.experiments || []).map(e => e.experiment_id);
  } catch (e) { return ['1','2']; }
}

async function getMLflowRecent(n=3) {
  try {
    const ids = await getMLflowExperimentIds.call(this);
    if (!ids.length) return [];
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: `${MLFLOW_URL}/api/2.0/mlflow/runs/search`,
      body: { experiment_ids: ids, max_results: n, order_by: ['start_time DESC'] },
      json: true,
      timeout: 5000,
      failOnNotOk: false,
    });
    return r.runs || [];
  } catch (e) { return []; }
}

// ---- FORMATTERS (HTML) ----
function fmtUptime(s) {
  if (!s) return '0s';
  const h = Math.floor(s/3600), m = Math.floor((s%3600)/60), x = s%60;
  return h ? `${h}h${String(m).padStart(2,'0')}m` : (m ? `${m}m${x}s` : `${x}s`);
}

function fmtETA(seconds) {
  if (!seconds || seconds < 0 || !isFinite(seconds)) return '?';
  if (seconds < 60) return `${Math.round(seconds)}s`;
  const h = Math.floor(seconds/3600);
  const m = Math.round((seconds%3600)/60);
  return h ? `${h}h${m}m` : `${m}m`;
}

function fmtRunPod(pod) {
  if (!pod) return 'pod not found';
  if (pod._error) return `error: ${esc(pod._error)}`;
  const rt = pod.runtime;
  if (!rt) return `pod <b>${esc(pod.desiredStatus)}</b> (no runtime)`;
  const g = rt.gpus?.[0] || {};
  const cost = (rt.uptimeInSeconds * pod.costPerHr / 3600).toFixed(2);
  return `<b>${esc(pod.name)}</b> ${esc(pod.desiredStatus)}\n` +
         `  uptime: ${fmtUptime(rt.uptimeInSeconds)}  cost: $${cost}\n` +
         `  gpu: ${g.gpuUtilPercent ?? '?'}%  mem: ${g.memoryUtilPercent ?? '?'}%`;
}

function fmtMLflowRuns(runs) {
  if (!runs.length) return '<i>no recent runs</i>';
  return runs.map(r => {
    const m = (r.data?.metrics || []).reduce((a,x) => (a[x.key]=x.value, a), {});
    const p = (r.data?.params || []).reduce((a,x) => (a[x.key]=x.value, a), {});
    const name = (r.info.run_name || '?').slice(0,50);
    const sts = r.info.status;
    const ts = m.timesteps;
    const total = parseFloat(p.total_timesteps);
    const sps = m.steps_per_s;
    const rew = m.rollout_ep_rew_mean;
    const succ = m.final_overall_success_rate;
    const dev = p.device;
    let line = `<code>${esc(name)}</code> ${esc(sts)}`;
    if (ts != null && total > 0) {
      const pct = (ts / total * 100).toFixed(0);
      line += `  ${(ts/1000).toFixed(0)}K/${(total/1e6).toFixed(1)}M (${pct}%)`;
      if (sts === 'RUNNING' && sps > 0) line += ` ETA ${fmtETA((total - ts) / sps)}`;
    } else if (ts != null) {
      line += `  ${(ts/1000).toFixed(0)}K steps`;
    }
    if (rew != null) line += `  rew=${rew.toFixed(0)}`;
    if (succ != null) line += `  <b>succ=${(succ*100).toFixed(0)}%</b>`;
    if (dev && dev !== '?') line += `  [${esc(dev)}]`;
    return '  ' + line;
  }).join('\n');
}

// ---- COMMAND DISPATCH ----
async function handleCommand(message) {
  const chat_id = message.chat?.id;
  // Silent drop on unauthorized — do NOT echo (avoids leaking bot identity)
  if (!ALLOWED_CHAT_IDS.includes(chat_id)) return null;

  const text = (message.text || '').trim();
  const tokens = text.split(/\s+/);
  const cmd = tokens[0].toLowerCase();
  const args = tokens.slice(1);
  let reply = '';

  if (cmd === '/start' || cmd === '/help') {
    reply = `<b>Triple Pendulum Bot</b> — commands:\n\n` +
      `<code>/status</code> — overall pipeline\n` +
      `<code>/runpod</code> — pod state + GPU + cost\n` +
      `<code>/ct1018</code> — local launcher sessions\n` +
      `<code>/mlflow [n]</code> — last n MLflow runs\n` +
      `<code>/gpu</code> — GPU one-liner\n` +
      `<code>/cost</code> — current cost + RunPod balance\n` +
      `<code>/launch &lt;m2|m3b|m3c|m4&gt;</code> — launch on CT 1018\n` +
      `<code>/kill ct1018|runpod</code> — kill running training\n` +
      `<code>/pod_start</code> — resume RunPod pod\n` +
      `<code>/pod_stop confirm</code> — stop RunPod pod (requires <code>confirm</code>)\n` +
      `<code>/help</code> — this message`;
  }
  else if (cmd === '/status') {
    const [pod, launcher, runs] = await Promise.all([
      getRunPodStatus.call(this), getLauncherStatus.call(this), getMLflowRecent.call(this, 3),
    ]);
    reply = `<b>Triple Pendulum status</b>\n\n` +
      `🌐 <b>RunPod</b>\n${fmtRunPod(pod)}\n\n` +
      `🖥 <b>CT 1018 launcher</b>\n  ${launcher._error ? esc(launcher._error) : `${launcher.count || 0} active processes`}\n\n` +
      `📊 <b>MLflow</b> (latest)\n${fmtMLflowRuns(runs)}`;
  }
  else if (cmd === '/runpod') {
    const pod = await getRunPodStatus.call(this);
    reply = `🌐 <b>RunPod</b>\n${fmtRunPod(pod)}`;
  }
  else if (cmd === '/ct1018') {
    const launcher = await getLauncherStatus.call(this);
    if (launcher._error) reply = `🖥 <b>CT 1018</b> — ${esc(launcher._error)}`;
    else {
      const sessions = (launcher.sessions || []).slice(0,3).map(s => `  • <code>${esc(s.slice(0,80))}</code>`).join('\n');
      reply = `🖥 <b>CT 1018</b> — ${launcher.count} active\n${sessions || '  <i>none</i>'}`;
    }
  }
  else if (cmd === '/mlflow') {
    const n = parseInt(args[0]) || 3;
    const runs = await getMLflowRecent.call(this, Math.min(Math.max(n, 1), 10));
    reply = `📊 <b>MLflow</b> — last ${runs.length}\n${fmtMLflowRuns(runs)}`;
  }
  else if (cmd === '/gpu') {
    const pod = await getRunPodStatus.call(this);
    if (!pod || pod._error) reply = `RunPod: ${esc(pod?._error || 'not reachable')}`;
    else {
      const g = pod.runtime?.gpus?.[0];
      reply = g ? `GPU ${g.gpuUtilPercent}% util / ${g.memoryUtilPercent}% mem` : 'no runtime';
    }
  }
  else if (cmd === '/cost') {
    const [pod, balance] = await Promise.all([getRunPodStatus.call(this), getRunPodBalance.call(this)]);
    let podPart = 'RunPod: not reachable';
    if (pod && !pod._error) {
      const cost = pod.runtime ? (pod.runtime.uptimeInSeconds * pod.costPerHr / 3600) : 0;
      podPart = `<b>${esc(pod.name)}</b> ${esc(pod.desiredStatus)}\n  current run cost: $${cost.toFixed(2)} (\$${pod.costPerHr}/hr)`;
    }
    const balPart = balance != null ? `\n\n💳 RunPod balance: <b>$${balance.toFixed(2)}</b>` : '';
    reply = `💰 <b>Cost</b>\n${podPart}${balPart}`;
  }
  else if (cmd === '/launch') {
    const stage = (args[0] || '').toLowerCase();
    const stageMap = {
      'm2':  { module: 'training.train_m2_upright',     config: 'training/configs/m2_upright_tqc.yaml' },
      'm3b': { module: 'training.train_m3_all_eps',     config: 'training/configs/m3b_all_eps_tqc.yaml' },
      'm3c': { module: 'training.train_m3_all_eps',     config: 'training/configs/m3c_all_eps_tqc.yaml' },
      'm4':  { module: 'training.train_m4_transitions', config: 'training/configs/m4_transitions_tqc.yaml' },
    };
    if (!stageMap[stage]) {
      reply = `Unknown stage: <code>${esc(stage)}</code>\nValid: m2, m3b, m3c, m4`;
    } else {
      // Ack immediately so user knows the request was received
      await tgSend.call(this, chat_id, `⏳ Launching <b>${stage.toUpperCase()}</b> on CT 1018...`);
      try {
        const r = await this.helpers.httpRequest({
          method: 'POST',
          url: `${LAUNCHER_URL}/launch`,
          body: { secret: LAUNCHER_SECRET, ...stageMap[stage] },
          json: true,
          timeout: 15000,
          failOnNotOk: false,
          returnFullResponse: true,
        });
        const body = r.body || r;
        if (body.ok) {
          reply = `✅ Launched <b>${esc(stage.toUpperCase())}</b>\nsession: <code>${esc(body.session)}</code>`;
        } else {
          const code = r.statusCode || 'err';
          reply = `❌ Launch failed (HTTP ${code})\n${esc(body.error || JSON.stringify(body))}`;
          if (body.sessions) reply += `\n<i>active:</i>\n` + body.sessions.slice(0,2).map(s => `  • <code>${esc(s.slice(0,80))}</code>`).join('\n');
        }
      } catch (e) {
        reply = `❌ Launcher error: ${esc(String(e).slice(0,200))}`;
      }
    }
  }
  else if (cmd === '/kill') {
    const target = (args[0] || '').toLowerCase();
    if (target === 'ct1018') {
      await tgSend.call(this, chat_id, `⚠️ Killing CT 1018 training...`);
      try {
        const r = await this.helpers.httpRequest({
          method: 'POST',
          url: `${LAUNCHER_URL}/kill`,
          body: { secret: LAUNCHER_SECRET },
          json: true,
          timeout: 10000,
          failOnNotOk: false,
          returnFullResponse: true,
        });
        const body = r.body || r;
        if (body.ok) {
          reply = `🛑 CT 1018 killed\n  sessions: ${(body.killed_sessions||[]).join(', ') || '<i>none</i>'}\n  pids: ${(body.killed_pids||[]).join(', ') || '<i>none</i>'}`;
        } else {
          reply = `❌ Kill failed: ${esc(body.error || JSON.stringify(body))}`;
        }
      } catch (e) {
        reply = `❌ Kill error: ${esc(String(e).slice(0,200))}`;
      }
    } else if (target === 'runpod') {
      await tgSend.call(this, chat_id, `⚠️ Stopping RunPod pod (kills training)...`);
      try {
        const r = await gqlRunPod.call(this, `mutation { podStop(input: {podId: "${RUNPOD_POD_ID}"}) { id desiredStatus } }`);
        const s = r.data?.podStop?.desiredStatus;
        reply = s ? `🛑 RunPod stopped: <b>${esc(s)}</b>` : `❌ stop failed: ${esc(JSON.stringify(r).slice(0,200))}`;
      } catch (e) { reply = `❌ ${esc(String(e).slice(0,200))}`; }
    } else {
      reply = `<code>/kill ct1018</code> or <code>/kill runpod</code>\n` +
              `<i>ct1018 sends TERM to local tmux + python; runpod stops the pod.</i>`;
    }
  }
  else if (cmd === '/pod_start') {
    try {
      const r = await gqlRunPod.call(this, `mutation { podResume(input: {podId: "${RUNPOD_POD_ID}", gpuCount: 1}) { id desiredStatus } }`);
      const s = r.data?.podResume?.desiredStatus;
      reply = s ? `🌐 RunPod resumed: <b>${esc(s)}</b>` : `❌ resume failed: ${esc(JSON.stringify(r).slice(0,200))}`;
    } catch (e) { reply = `❌ ${esc(String(e).slice(0,200))}`; }
  }
  else if (cmd === '/pod_stop') {
    if (args[0] !== 'confirm') {
      reply = `⚠️ <b>/pod_stop</b> stops the RunPod pod and KILLS any running training.\n\n` +
              `To confirm: <code>/pod_stop confirm</code>`;
    } else {
      try {
        const r = await gqlRunPod.call(this, `mutation { podStop(input: {podId: "${RUNPOD_POD_ID}"}) { id desiredStatus } }`);
        const s = r.data?.podStop?.desiredStatus;
        reply = s ? `🛑 RunPod stopped: <b>${esc(s)}</b>` : `❌ stop failed: ${esc(JSON.stringify(r).slice(0,200))}`;
      } catch (e) { reply = `❌ ${esc(String(e).slice(0,200))}`; }
    }
  }
  else {
    reply = `Unknown command: <code>${esc(cmd)}</code>\nTry <code>/help</code>`;
  }
  return { chat_id, text: reply };
}

const items = [];
for (const upd of updates) {
  const msg = upd.message;
  if (!msg || !msg.text) continue;
  const r = await handleCommand.call(this, msg);
  if (!r) continue;
  items.push({ json: { ...r, parse_mode: 'HTML', disable_web_page_preview: true, telegramBotUrl: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage` } });
}
return items;
